import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Read the entire line instead of a single token

        StringBuilder buffer = new StringBuilder(name);

        // Check if the buffer size exceeds a certain limit
        if (buffer.length() > 10) {
            System.out.println("Input exceeds maximum length. Please try again.");
            return;
        }

        System.out.println("Welcome, " + buffer.toString());
    }
}

